module traffic_light(
    input rst_n,
    input clk,
    input pass_request,
    output reg red,
    output reg yellow,
    output reg green,
    output reg red,
    output reg yellow,
    output reg green,
    output reg state,
    output reg red,
    output reg yellow,
    output reg green,
    output reg state,
    output reg red,
    output reg yellow,
    output reg green,
    output reg state,
    output reg red,
    output reg yellow,
    output reg green,
    output reg state,
    input rst_n,
    output reg red,
    output reg yellow,
    output reg green
);

    parameter GREEN_TIME = 60;
    parameter YELLOW_TIME = 5;
    parameter RED_TIME = 10;

    reg [7:0] timer;
    reg [1:0] state;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            timer <= 0;
            state <= 2'b00;
            red <= 1'b0;
            yellow <= 1'b0;
            green <= 1'b0;
        end else begin
            case (state)
                2'b00: begin // Idle state
                    red <= 1'b0;
                    yellow <= 1'b0;
                    green <= 1'b0;
                    if (pass_request) begin
                        state <= 2'b01; // Transition to red state
                        timer <= RED_TIME;
                    end else begin
                        state <= 2'b11; // Transition to green state
                        timer <= GREEN_TIME;
                    end
                end
                2'b01: begin // Red state
                    red <= 1'b1;
                    yellow <= 1'b0;
                    green <= 1'b0;
                    if (timer == 0) begin
                        state <= 2'b10; // Transition to yellow state
                        timer <= YELLOW_TIME;
                    end else begin
                        timer <= timer - 1;
                    end
                end
                2'b10: begin // Yellow state
                    red <= 1'b0;
                    yellow <= 1'b1;
                    green <= 1'b0;
                    if (timer == 0) begin
                        state <= 2'b11; // Transition to green state
                        timer <= GREEN_TIME;
                    end else begin
                        timer <= timer - 1;
                    end
                end
                2'b11: begin // Green state
                    red <= 1'b0;
                    yellow <= 1'b0;
                    green <= 1'b1;
                    if (timer == 0 || pass_request) begin
                        state <= 2'b01; // Transition to red state
                        timer <= RED_TIME;
                    end else begin
                        timer <= timer - 1;
                    end
                end
            endcase
        end
    end

endmodule
